namespace BlazorApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;
    private readonly Lock _lock = new();

    private readonly List<Notification> _notifications =
    [
        new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)),
        new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)),
        new(3, "New feature available: dark mode.", DateTime.UtcNow.AddMinutes(-1)),
    ];

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        lock (_lock)
        {
            // Simulate occasional new notifications
            if (Random.Shared.Next(3) == 0)
            {
                var id = _nextId++;
                _notifications.Add(new Notification(id, $"New alert #{id} just arrived!", DateTime.UtcNow));
            }

            return Task.FromResult(
                _notifications
                    .Where(n => n.Timestamp > since)
                    .OrderByDescending(n => n.Timestamp)
                    .ToList());
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (AllNotifications is not null)
    {
        <span class="badge bg-primary ms-2">@AllNotifications.Count</span>
    }
</h1>

@if (AllNotifications is null)
{
    <p><em>Loading...</em></p>
}
else if (AllNotifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in AllNotifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;
    private DateTime _lastCheck;

    [PersistentState]
    public List<Notification>? AllNotifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we only fetch if state wasn't restored from prerender
        AllNotifications ??= await NotificationService.GetNotificationsAsync();
        _lastCheck = AllNotifications.Count > 0
            ? AllNotifications.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender is never called during prerender, so this is safe
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newer = await NotificationService.GetNotificationsSinceAsync(_lastCheck);
            if (newer.Count > 0)
            {
                _lastCheck = newer.Max(n => n.Timestamp);
                AllNotifications = newer.Concat(AllNotifications!).ToList();
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

