<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (_notifications is not null)
    {
        <span class="badge bg-primary ms-2">@_notifications.Count</span>
    }
</h1>

@if (_notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (_notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private const string PersistenceKey = "notifications";
    private List<Notification>? _notifications;
    private PersistingComponentStateSubscription _persistSub;
    private CancellationTokenSource? _cts;
    private DateTime _lastCheck;

    protected override async Task OnInitializedAsync()
    {
        _persistSub = ApplicationState.RegisterOnPersisting(PersistNotifications);

        if (!ApplicationState.TryTakeFromJson<List<Notification>>(PersistenceKey, out var restored))
        {
            _notifications = await NotificationService.GetNotificationsAsync();
        }
        else
        {
            _notifications = restored;
        }

        _lastCheck = _notifications is { Count: > 0 }
            ? _notifications.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    private Task PersistNotifications()
    {
        ApplicationState.PersistAsJson(PersistenceKey, _notifications);
        return Task.CompletedTask;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender is never called during prerender — safe to start polling
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var newer = await NotificationService.GetNotificationsSinceAsync(_lastCheck);
                if (newer.Count > 0)
                {
                    _lastCheck = newer.Max(n => n.Timestamp);
                    _notifications = newer.Concat(_notifications!).ToList();
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _persistSub.Dispose();
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

